return items.map(item => {
  let parsed = {};
  try {
    parsed = JSON.parse(item.json.data);
  } catch (e) {
    parsed = { error: "JSON inválido", raw: item.json.data };
  }
  return { json: parsed };
});

function normalizarTexto(texto) {
  return texto
    ? texto
        .normalize("NFD") // separa letras e acentos
        .replace(/[\u0300-\u036f]/g, "") // remove os acentos
        .trim()
        .toLowerCase()
    : "";
}

return items.map(item => {
  const motivo = item.json.motivo || "";
  item.json.motivo_normalizado = normalizarTexto(motivo);
  return item;
});

